sql:
SELECT year, average_firearms_per_100_people
FROM firearm_statistics
WHERE year = 2012;

SELECT guns_per_100_inhabitants, number_of_mass_shootings
FROM firearm_statistics
WHERE country_id = 0 AND year = 2012;

external_knowledge:
- Mass shootings are typically defined as incidents where at least 4 people are shot, not including the shooter, and may or may not be fatal; 
- The years 2010 to 2020 are considered for this analysis; 
- Firearm ownership rate is often considered a contributing factor to mass shootings; 
- This analysis aims to identify countries that may need stricter gun control policies.

sql:
SELECT COUNT(shooting_id) AS total_mass_shootings
FROM mass_shootings
WHERE year = 2012;

SELECT AVG(average_firearms_per_100_people) AS avg_firearms_per_100_people
   FROM firearm_statistics
   WHERE year = (SELECT MAX(year) FROM firearm_statistics);
